sql:
SELECT AVG(metric_value) AS average_market_cap
FROM financial_metrics
WHERE metric_name = 'Market Cap';

SELECT AVG(statement_value) AS average_income_statement_value
FROM financial_statements
WHERE statement_name = 'Income Statement' AND statement_period LIKE 'Q1 %';

SELECT company_name, company_employees
FROM companies
WHERE company_employees > 100000;

external_knowledge:
- 'ancient giants' metaphorically refers to companies founded before the year 2000;
- 'forest of industry 1' is a metaphor for the specific sector (sector_id 1);
- 'stood strong for over two decades' refers to companies that were founded over 20 years before 2022, i.e., before 2000;
- 'as of the end of 2022' indicates the time frame for the recorded metrics.
